def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / bin_capacity
        if ratio > 1:
            priorities[i] = float('inf')
        else:
            score = 0
            for j in range(1, 5):
                partial_ratio = ratio ** j
                if partial_ratio < 0.5:
                    score += (1 / (j + 1)) * (1 - partial_ratio)
                else:
                    score += (j) * partial_ratio
            if score > 2.5:
                priorities[i] = score * 2 - np.log(bin_capacity + 1)
            else:
                if bin_capacity > 50:
                    priorities[i] = score + np.sin(bin_capacity)
                else:
                    priorities[i] = score - np.cos(item)
    return priorities
